33: // WithTracing adds tracing to requests if the incoming request is sampled
34: func WithTracing(handler http.Handler, tp trace.TracerProvider) http.Handler {
35: 	opts := []otelhttp.Option{
36: 		otelhttp.WithPropagators(tracing.Propagators()),
37: 		otelhttp.WithPublicEndpointFn(notSystemPrivilegedGroup),
38: 		otelhttp.WithTracerProvider(tp),
39: 		otelhttp.WithSpanNameFormatter(func(operation string, r *http.Request) string {
40: 			ctx := r.Context()
41: 			info, exist := request.RequestInfoFrom(ctx)
42: 			if !exist || !info.IsResourceRequest {
43: 				return r.Method
44: 			}
45: 			return getSpanNameFromRequestInfo(info, r)
46: 		}),
47: 	}
48: 	wrappedHandler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
49: 		// Adjust otelhttp tracing start time to match the start time used
50: 		// for Prometheus metrics.
51: 		if startTime, ok := request.ReceivedTimestampFrom(r.Context()); ok {
52: 			r = r.WithContext(otelhttp.ContextWithStartTime(r.Context(), startTime))
53: 		}
54: 		// Add the http.target attribute to the otelhttp span
55: 		// Workaround for https://github.com/open-telemetry/opentelemetry-go-contrib/issues/3743
56: 		span := trace.SpanFromContext(r.Context())
57: 		if r.URL != nil {
58: 			span.SetAttributes(semconv.HTTPTarget(r.URL.RequestURI()))
59: 		}
60: 		// Add auditID attribute if available. This helps us connect traces to audit log entries
61: 		span.SetAttributes(attribute.String("audit-id", audit.GetAuditIDTruncated(r.Context())))
62: 		handler.ServeHTTP(w, r)
63: 	})
64: 	// With Noop TracerProvider, the otelhttp still handles context propagation.
65: 	// See https://github.com/open-telemetry/opentelemetry-go/tree/main/example/passthrough
66: 	return otelhttp.NewHandler(wrappedHandler, "KubernetesAPI", opts...)
67: }
68: 
69: func getSpanNameFromRequestInfo(info *request.RequestInfo, r *http.Request) string {
70: 	spanName := "/" + info.APIPrefix
71: 	if info.APIGroup != "" {
72: 		spanName += "/" + info.APIGroup
73: 	}
74: 	spanName += "/" + info.APIVersion
75: 	if info.Namespace != "" {
76: 		spanName += "/namespaces/{:namespace}"
77: 	}
78: 	spanName += "/" + info.Resource
79: 	if info.Name != "" {
80: 		spanName += "/" + "{:name}"
81: 	}
82: 	if info.Subresource != "" {
83: 		spanName += "/" + info.Subresource
84: 	}
85: 	return r.Method + " " + spanName
86: }
87: 
88: func notSystemPrivilegedGroup(req *http.Request) bool {
89: 	if u, ok := request.UserFrom(req.Context()); ok {
90: 		for _, group := range u.GetGroups() {
91: 			if group == user.SystemPrivilegedGroup || group == user.MonitoringGroup {
92: 				return false
93: 			}
94: 		}
95: 	}
96: 	return true
97: }
