130: func (ots *TracingService) initJaegerTracerProvider() (*tracesdk.TracerProvider, error) {
131: 	var ep jaeger.EndpointOption
132: 	// Create the Jaeger exporter: address can be either agent address (host:port) or collector URL
133: 	if strings.HasPrefix(ots.cfg.Address, "http://") || strings.HasPrefix(ots.cfg.Address, "https://") {
134: 		ots.log.Debug("using jaeger collector", "address", ots.cfg.Address)
135: 		ep = jaeger.WithCollectorEndpoint(jaeger.WithEndpoint(ots.cfg.Address))
136: 	} else if host, port, err := net.SplitHostPort(ots.cfg.Address); err == nil {
137: 		ots.log.Debug("using jaeger agent", "host", host, "port", port)
138: 		ep = jaeger.WithAgentEndpoint(jaeger.WithAgentHost(host), jaeger.WithAgentPort(port), jaeger.WithMaxPacketSize(64000))
139: 	} else {
140: 		return nil, fmt.Errorf("invalid tracer address: %s", ots.cfg.Address)
141: 	}
142: 	exp, err := jaeger.New(ep)
143: 	if err != nil {
144: 		return nil, err
145: 	}
146: 
147: 	res, err := resource.New(
148: 		context.Background(),
149: 		resource.WithAttributes(
150: 			// TODO: why are these attributes different from ones added to the
151: 			// OTLP provider?
152: 			semconv.ServiceNameKey.String(ots.cfg.ServiceName),
153: 			attribute.String("environment", "production"),
154: 		),
155: 		resource.WithAttributes(ots.cfg.CustomAttribs...),
156: 	)
157: 	if err != nil {
158: 		return nil, err
159: 	}
160: 
161: 	sampler, err := ots.initSampler()
162: 	if err != nil {
163: 		return nil, err
164: 	}
165: 
166: 	tp := tracesdk.NewTracerProvider(
167: 		tracesdk.WithBatcher(exp),
168: 		tracesdk.WithResource(res),
169: 		tracesdk.WithSampler(sampler),
170: 	)
171: 
172: 	return tp, nil
173: }
