175: func (ots *TracingService) initOTLPTracerProvider() (*tracesdk.TracerProvider, error) {
176: 	opts := []otlptracegrpc.Option{otlptracegrpc.WithEndpoint(ots.cfg.Address)}
177: 	if ots.cfg.Insecure {
178: 		opts = append(opts, otlptracegrpc.WithInsecure())
179: 	} else {
180: 		opts = append(opts, otlptracegrpc.WithTLSCredentials(credentials.NewTLS(nil)))
181: 	}
182: 
183: 	client := otlptracegrpc.NewClient(opts...)
184: 	exp, err := otlptrace.New(context.Background(), client)
185: 	if err != nil {
186: 		return nil, err
187: 	}
188: 
189: 	sampler, err := ots.initSampler()
190: 	if err != nil {
191: 		return nil, err
192: 	}
193: 
194: 	return initTracerProvider(exp, ots.cfg.ServiceName, ots.cfg.ServiceVersion, sampler, ots.cfg.CustomAttribs...)
195: }
