197: func (ots *TracingService) initSampler() (tracesdk.Sampler, error) {
198: 	switch ots.cfg.Sampler {
199: 	case "const", "":
200: 		if ots.cfg.SamplerParam >= 1 {
201: 			return tracesdk.AlwaysSample(), nil
202: 		} else if ots.cfg.SamplerParam <= 0 {
203: 			return tracesdk.NeverSample(), nil
204: 		}
205: 
206: 		return nil, fmt.Errorf("invalid param for const sampler - must be 0 or 1: %f", ots.cfg.SamplerParam)
207: 	case "probabilistic":
208: 		return tracesdk.TraceIDRatioBased(ots.cfg.SamplerParam), nil
209: 	case "rateLimiting":
210: 		return newRateLimiter(ots.cfg.SamplerParam), nil
211: 	case "remote":
212: 		return jaegerremote.New(ots.cfg.ServiceName,
213: 			jaegerremote.WithSamplingServerURL(ots.cfg.SamplerRemoteURL),
214: 			jaegerremote.WithInitialSampler(tracesdk.TraceIDRatioBased(ots.cfg.SamplerParam)),
215: 		), nil
216: 	default:
217: 		return nil, fmt.Errorf("invalid sampler type: %s", ots.cfg.Sampler)
218: 	}
219: }
