221: func initTracerProvider(exp tracesdk.SpanExporter, serviceName string, serviceVersion string, sampler tracesdk.Sampler, customAttribs ...attribute.KeyValue) (*tracesdk.TracerProvider, error) {
222: 	res, err := resource.New(
223: 		context.Background(),
224: 		resource.WithAttributes(
225: 			semconv.ServiceNameKey.String(serviceName),
226: 			semconv.ServiceVersionKey.String(serviceVersion),
227: 		),
228: 		resource.WithAttributes(customAttribs...),
229: 		resource.WithFromEnv(),
230: 		resource.WithProcessRuntimeDescription(),
231: 		resource.WithTelemetrySDK(),
232: 	)
233: 	if err != nil {
234: 		return nil, err
235: 	}
236: 
237: 	tp := tracesdk.NewTracerProvider(
238: 		tracesdk.WithBatcher(exp),
239: 		tracesdk.WithSampler(tracesdk.ParentBased(sampler)),
240: 		tracesdk.WithResource(res),
241: 	)
242: 	return tp, nil
243: }
