249: func (ots *TracingService) initOpentelemetryTracer() error {
250: 	var tp tracerProvider
251: 	var err error
252: 	switch ots.cfg.enabled {
253: 	case jaegerExporter:
254: 		tp, err = ots.initJaegerTracerProvider()
255: 		if err != nil {
256: 			return err
257: 		}
258: 	case otlpExporter:
259: 		tp, err = ots.initOTLPTracerProvider()
260: 		if err != nil {
261: 			return err
262: 		}
263: 	default:
264: 		tp, err = ots.initNoopTracerProvider()
265: 		if err != nil {
266: 			return err
267: 		}
268: 	}
269: 
270: 	if ots.cfg.ProfilingIntegration {
271: 		tp = NewProfilingTracerProvider(tp)
272: 	}
273: 
274: 	// Register our TracerProvider as the global so any imported
275: 	// instrumentation in the future will default to using it
276: 	// only if tracing is enabled
277: 	if ots.cfg.enabled != "" {
278: 		otel.SetTracerProvider(tp)
279: 	}
280: 
281: 	propagators := []propagation.TextMapPropagator{}
282: 	for _, p := range strings.Split(ots.cfg.Propagation, ",") {
283: 		switch p {
284: 		case w3cPropagator:
285: 			propagators = append(propagators, propagation.TraceContext{}, propagation.Baggage{})
286: 		case jaegerPropagator:
287: 			propagators = append(propagators, jaegerpropagator.Jaeger{})
288: 		case "":
289: 		default:
290: 			return fmt.Errorf("unsupported OpenTelemetry propagator: %q", p)
291: 		}
292: 	}
293: 
294: 	switch len(propagators) {
295: 	case 0:
296: 		otel.SetTextMapPropagator(propagation.NewCompositeTextMapPropagator(
297: 			propagation.TraceContext{}, propagation.Baggage{},
298: 		))
299: 	case 1:
300: 		otel.SetTextMapPropagator(propagators[0])
301: 	default:
302: 		otel.SetTextMapPropagator(propagation.NewCompositeTextMapPropagator(propagators...))
303: 	}
304: 
305: 	if ots.tracerProvider == nil {
306: 		ots.tracerProvider = tp
307: 	}
308: 
309: 	ots.Tracer = otel.GetTracerProvider().Tracer("component-main")
310: 
311: 	return nil
312: }
