405: func ServerTimingForSpan(span trace.Span) string {
406: 	spanCtx := span.SpanContext()
407: 	if !spanCtx.HasTraceID() || !spanCtx.IsValid() {
408: 		return ""
409: 	}
410: 
411: 	return fmt.Sprintf("00-%s-%s-01", spanCtx.TraceID().String(), spanCtx.SpanID().String())
412: }
